void insert(Token.Character characterToken) {
    Node node;
    // characters in script and style go in as datanodes, not text nodes
    final String tagName = currentElement().tagName();
    String data = characterToken.getData();

    // Handle the special case for PRE tags: skip the first newline character if present
    if (shouldSkipFirstNewlineInPre && tagName.equals("pre") && data != null && !data.isEmpty()) {
        // Check if the data starts with a newline character (\n, \r, or \r\n)
        if (data.charAt(0) == '\n') {
            data = data.substring(1); // Skip the first character which is \n
        } else if (data.charAt(0) == '\r') {
            if (data.length() > 1 && data.charAt(1) == '\n') {
                data = data.substring(2); // Skip \r\n sequence
            } else {
                data = data.substring(1); // Skip just the \r
            }
        }
        // If we've consumed the entire string after skipping the newline, don't insert anything
        if (data.isEmpty()) {
            shouldSkipFirstNewlineInPre = false; // Reset the flag
            return;
        }
        shouldSkipFirstNewlineInPre = false; // Reset the flag after handling
    }

    if (characterToken.isCData())
        node = new CDataNode(data);
    else if (tagName.equals("script") || tagName.equals("style"))
        node = new DataNode(data);
    else
        node = new TextNode(data);
    currentElement().appendChild(node); // doesn't use insertNode, because we don't foster these; and will always have a stack.
}

